// src/App.jsx
import { useState, useEffect } from "react";
import "./styles/global.css";

import Navbar from "./components/Navbar";
import Hero from "./components/Hero";
import Features from "./components/Features";
import PostsSection from "./components/PostsSection";
import { About, Footer } from "./components/About";
import WriteModal from "./components/WriteModal";
import PostReader from "./components/PostReader";
import { usePosts } from "./hooks/usePosts";

// Loading Screen
function LoadingScreen({ done }) {
  return (
    <div
      style={{
        position: "fixed", inset: 0, zIndex: 9999,
        background: "#0c0c14",
        display: "flex", flexDirection: "column",
        alignItems: "center", justifyContent: "center", gap: 20,
        transition: "opacity 0.6s, visibility 0.6s",
        opacity: done ? 0 : 1,
        visibility: done ? "hidden" : "visible",
      }}
    >
      <div style={{
        fontFamily: "var(--font-display)",
        fontSize: "2.2rem", fontWeight: 800,
        color: "#fff", letterSpacing: "-1px",
        display: "flex", alignItems: "center", gap: 2,
      }}>
        AERO<span style={{ color: "#1d4ed8" }}>BLOG</span>
        <span style={{
          width: 10, height: 10, background: "#f5c518",
          borderRadius: "50%", marginLeft: 4,
          animation: "pulse 1.2s ease-in-out infinite",
        }} />
      </div>
      <div style={{
        width: 200, height: 3,
        background: "rgba(255,255,255,0.1)",
        borderRadius: 2, overflow: "hidden",
      }}>
        <div style={{
          height: "100%", background: "#1d4ed8",
          borderRadius: 2,
          animation: "progressFill 1.4s ease forwards",
        }} />
      </div>
      <p style={{
        fontSize: "0.78rem", color: "rgba(255,255,255,0.3)",
        fontFamily: "var(--font-display)", letterSpacing: "0.05em",
        textTransform: "uppercase",
      }}>
        Connecting to Firebase…
      </p>
    </div>
  );
}

// Toast notification
function Toast({ message, show }) {
  return (
    <div style={{
      position: "fixed", bottom: 24, right: 24, zIndex: 999,
      background: "#0c0c14", color: "#fff",
      padding: "14px 22px", borderRadius: 12,
      fontFamily: "var(--font-display)", fontWeight: 600, fontSize: "0.9rem",
      display: "flex", alignItems: "center", gap: 10,
      boxShadow: "0 8px 30px rgba(0,0,0,0.3)",
      transform: show ? "translateX(0)" : "translateX(120%)",
      opacity: show ? 1 : 0,
      transition: "all 0.35s ease",
    }}>
      ✅ Post published successfully!
    </div>
  );
}

export default function App() {
  const [loadingDone, setLoadingDone] = useState(false);
  const [showWrite, setShowWrite] = useState(false);
  const [selectedPost, setSelectedPost] = useState(null);
  const [showToast, setShowToast] = useState(false);

  const { posts, loading, isDemo, addDemoPost } = usePosts();

  useEffect(() => {
    const t = setTimeout(() => setLoadingDone(true), 1600);
    return () => clearTimeout(t);
  }, []);

  const handlePublished = () => {
    setShowToast(true);
    setTimeout(() => setShowToast(false), 3500);
  };

  const handleDemoPublish = (postData) => {
    addDemoPost(postData);
    handlePublished();
  };

  const scrollToPosts = () => {
    document.getElementById("posts")?.scrollIntoView({ behavior: "smooth" });
  };

  return (
    <>
      <LoadingScreen done={loadingDone} />

      <Navbar
        onWriteClick={() => setShowWrite(true)}
        isDemo={isDemo}
      />

      <main>
        <Hero
          postCount={posts.length}
          onWriteClick={() => setShowWrite(true)}
          onExplore={scrollToPosts}
        />

        <Features />

        <PostsSection
          posts={posts}
          loading={loading}
          isDemo={isDemo}
          onOpenPost={setSelectedPost}
        />

        <About />
      </main>

      <Footer onWriteClick={() => setShowWrite(true)} />

      {showWrite && (
        <WriteModal
          onClose={() => setShowWrite(false)}
          onPublished={handlePublished}
          isDemo={isDemo}
          onDemoPublish={handleDemoPublish}
        />
      )}

      {selectedPost && (
        <PostReader
          post={selectedPost}
          onClose={() => setSelectedPost(null)}
        />
      )}

      <Toast show={showToast} />
    </>
  );
}
